/**
 * Unit tests for database email query service (T036h + T048)
 *
 * TODO (T086): Fix email-query schema and pagination issues
 * This test file has 3 failing tests due to schema mismatches and pagination bugs.
 * Complete T086 to fix:
 * - Line 260: "column sc.category_id does not exist" SQL error
 * - Line 348: Body text search not finding "invoice"
 * - Line 401: Pagination returning duplicate records
 *
 * TDD Approach: Write comprehensive tests FIRST covering:
 * - SQL query generation and execution
 * - Result mapping to EmailMessage interface
 * - Error handling and edge cases
 * - Basic filtering (date range, limit, unclassified) - T036h
 * - Criteria-based selection with query builder - T048
 * - Pagination with cursor-based paging - T048
 * - Performance optimization - T048
 */

import {
  fetchEmailsByDateRange,
  fetchEmailById,
  fetchUnclassifiedEmails,
  fetchEmailsByCriteria,
  type EmailQueryCriteria,
  type PaginationOptions,
  closePool,
} from '../../src/persistence/email-query';

describe('EmailQuery Service', () => {
  afterAll(async () => {
    await closePool();
  });

  describe('fetchEmailsByDateRange', () => {
    it('should fetch emails within specified date range', async () => {
      // Arrange
      const startDate = new Date('2025-09-01');
      const endDate = new Date('2025-09-30');
      const limit = 10;

      // Act
      const emails = await fetchEmailsByDateRange(startDate, endDate, limit);

      // Assert
      expect(Array.isArray(emails)).toBe(true);
      expect(emails.length).toBeLessThanOrEqual(limit);
      emails.forEach((email) => {
        expect(email).toMatchObject({
          id: expect.any(String),
          threadId: expect.any(String),
          subject: expect.any(String),
          from: expect.objectContaining({
            email: expect.any(String),
            raw: expect.any(String),
          }),
          date: expect.any(Date),
          isProcessed: expect.any(Boolean),
        });
        expect(email.date.getTime()).toBeGreaterThanOrEqual(startDate.getTime());
        expect(email.date.getTime()).toBeLessThanOrEqual(endDate.getTime());
      });
    });

    it('should respect limit parameter', async () => {
      const startDate = new Date('2025-01-01');
      const endDate = new Date('2025-12-31');
      const limit = 5;

      const emails = await fetchEmailsByDateRange(startDate, endDate, limit);

      expect(emails.length).toBeLessThanOrEqual(limit);
    });

    it('should return empty array when no emails in date range', async () => {
      const startDate = new Date('2020-01-01');
      const endDate = new Date('2020-01-02');

      const emails = await fetchEmailsByDateRange(startDate, endDate);

      expect(emails).toEqual([]);
    });

    it('should throw error for invalid date range', async () => {
      const startDate = new Date('2025-12-31');
      const endDate = new Date('2025-01-01'); // end before start

      await expect(fetchEmailsByDateRange(startDate, endDate)).rejects.toThrow(
        /Invalid date range|start date must be before end date/i
      );
    });

    it('should use default limit when not specified', async () => {
      const startDate = new Date('2025-01-01');
      const endDate = new Date('2025-12-31');

      const emails = await fetchEmailsByDateRange(startDate, endDate);

      // Should not throw and should have reasonable limit (100)
      expect(emails.length).toBeLessThanOrEqual(100);
    });
  });

  describe('fetchEmailById', () => {
    it('should fetch single email by message ID', async () => {
      // This test requires a known message ID from the database
      // We'll make it conditional on database availability
      // Test with mock ID (will throw if not found)
      const testId = 'test-message-id-12345';

      await expect(fetchEmailById(testId)).rejects.toThrow(/not found|does not exist/i);
    });

    it('should return complete EmailMessage structure', async () => {
      // Skip if no test data available
      // This would work with real data
      // const email = await fetchEmailById('real-id');
      // expect(email).toMatchObject({ id, subject, from, ... });
    });

    it('should throw error for null or empty message ID', async () => {
      await expect(fetchEmailById('')).rejects.toThrow(/message.*id.*required/i);
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      await expect(fetchEmailById(null as any)).rejects.toThrow(/message.*id.*required/i);
    });

    it('should handle database connection errors gracefully', async () => {
      // This will be tested with connection pool errors
      // Test will fail initially until implementation handles errors
      await expect(fetchEmailById('test-id')).rejects.toThrow();
    });
  });

  describe('fetchUnclassifiedEmails', () => {
    it('should fetch emails without classification_session records', async () => {
      const limit = 10;

      const emails = await fetchUnclassifiedEmails(limit);

      expect(Array.isArray(emails)).toBe(true);
      expect(emails.length).toBeLessThanOrEqual(limit);

      // All emails should not have processingSessionId
      emails.forEach((email) => {
        expect(email.processingSessionId).toBeUndefined();
        expect(email.isProcessed).toBe(false);
      });
    });

    it('should use default limit of 100 when not specified', async () => {
      const emails = await fetchUnclassifiedEmails();

      expect(emails.length).toBeLessThanOrEqual(100);
    });

    it('should return empty array when all emails are classified', async () => {
      // This may or may not return empty depending on database state
      const emails = await fetchUnclassifiedEmails(1);

      expect(Array.isArray(emails)).toBe(true);
    });
  });

  describe('Result Mapping', () => {
    it('should correctly map database columns to EmailMessage interface', async () => {
      const emails = await fetchEmailsByDateRange(new Date('2025-09-01'), new Date('2025-09-30'), 1);

      if (emails.length > 0) {
        const email = emails[0];

        // Required fields
        expect(email.id).toBeDefined();
        expect(email.threadId).toBeDefined();
        expect(email.subject).toBeDefined();
        expect(email.from).toBeDefined();
        expect(email.from.email).toBeDefined();
        expect(email.date).toBeInstanceOf(Date);
        expect(email.isProcessed).toBeDefined();
        expect(email.processingPriority).toBeDefined();

        // Payload structure
        expect(email.payload).toBeDefined();
        expect(email.payload.mimeType).toBeDefined();
        expect(Array.isArray(email.payload.headers)).toBe(true);

        // Gmail labels
        expect(Array.isArray(email.gmailLabels)).toBe(true);

        // Optional fields should be present but may be undefined
        expect(email).toHaveProperty('bodyPlain');
        expect(email).toHaveProperty('bodyHtml');
        expect(email).toHaveProperty('snippet');
      }
    });

    it('should parse JSON fields correctly', async () => {
      const emails = await fetchEmailsByDateRange(new Date('2025-09-01'), new Date('2025-09-30'), 1);

      if (emails.length > 0) {
        const email = emails[0];

        // payload should be object, not string
        expect(typeof email.payload).toBe('object');

        // gmailLabels should be array, not string
        expect(Array.isArray(email.gmailLabels)).toBe(true);

        // from should be object with email property
        expect(typeof email.from).toBe('object');
        expect(typeof email.from.email).toBe('string');
      }
    });
  });

  describe('Error Handling', () => {
    it('should provide meaningful error messages', async () => {
      await expect(fetchEmailById('')).rejects.toThrow(/message.*id.*required/i);
    });

    it('should handle database connection pool errors', async () => {
      // This will be tested when connection pool is unavailable
      // Implementation should wrap pg errors in meaningful messages
    });

    it('should handle malformed data in database', async () => {
      // Implementation should handle JSON parsing errors gracefully
      // and skip/log problematic records
    });
  });

  // ========== T048: Criteria-Based Selection Tests ==========

  describe('fetchEmailsByCriteria - T048', () => {
    describe('Basic Criteria Filtering', () => {
      it('should fetch emails with subject filter', async () => {
        const criteria: EmailQueryCriteria = {
          subject: 'Receipt',
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        result.items.forEach((email) => {
          expect(email.subject.toLowerCase()).toContain('receipt');
        });
      });

      it('should fetch emails with from address filter', async () => {
        const criteria: EmailQueryCriteria = {
          from: 'notifications@example.com',
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        result.items.forEach((email) => {
          expect(email.from.email.toLowerCase()).toContain('notifications@example.com');
        });
      });

      it('should fetch emails with category filter', async () => {
        const criteria: EmailQueryCriteria = {
          primaryCategory: 'financial',
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        // Note: requires JOIN with classification tables
      });

      it('should fetch emails with processing status filter', async () => {
        const criteria: EmailQueryCriteria = {
          isProcessed: false,
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        result.items.forEach((email) => {
          expect(email.isProcessed).toBe(false);
          expect(email.processingSessionId).toBeUndefined();
        });
      });

      it('should fetch emails with Gmail label filter', async () => {
        const criteria: EmailQueryCriteria = {
          gmailLabels: ['INBOX', 'UNREAD'],
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        result.items.forEach((email) => {
          const hasInbox = email.gmailLabels.includes('INBOX');
          const hasUnread = email.gmailLabels.includes('UNREAD');
          expect(hasInbox || hasUnread).toBe(true);
        });
      });

      it('should fetch emails with confidence threshold filter', async () => {
        const criteria: EmailQueryCriteria = {
          minConfidence: 0.8,
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        // Note: requires JOIN with classification results
      });
    });

    describe('Combined Criteria Filtering', () => {
      it('should apply multiple criteria with AND logic', async () => {
        const criteria: EmailQueryCriteria = {
          dateRange: {
            start: new Date('2025-09-01'),
            end: new Date('2025-09-30'),
          },
          from: 'example.com',
          isProcessed: true,
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        result.items.forEach((email) => {
          expect(email.date.getTime()).toBeGreaterThanOrEqual(criteria.dateRange!.start.getTime());
          expect(email.date.getTime()).toBeLessThanOrEqual(criteria.dateRange!.end.getTime());
          expect(email.from.email.toLowerCase()).toContain('example.com');
          expect(email.isProcessed).toBe(true);
        });
      });

      it('should handle empty criteria (fetch all with default pagination)', async () => {
        const criteria: EmailQueryCriteria = {};

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        expect(result.items.length).toBeLessThanOrEqual(50); // Default page size
      });

      it('should support body text search', async () => {
        const criteria: EmailQueryCriteria = {
          bodyContains: 'invoice',
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        result.items.forEach((email) => {
          const bodyText = (email.bodyPlain || email.bodyHtml || '').toLowerCase();
          expect(bodyText).toContain('invoice');
        });
      });

      it('should support urgency level filter', async () => {
        const criteria: EmailQueryCriteria = {
          urgency: 'high',
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
        // Note: requires JOIN with attribute context
      });
    });

    describe('Pagination', () => {
      it('should support limit-based pagination', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          limit: 10,
        };

        const result = await fetchEmailsByCriteria(criteria, pagination);

        expect(result.items.length).toBeLessThanOrEqual(10);
        expect(result.pagination.limit).toBe(10);
      });

      it('should support cursor-based pagination with nextCursor', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          limit: 5,
        };

        // Fetch first page
        const firstPage = await fetchEmailsByCriteria(criteria, pagination);

        expect(firstPage.items.length).toBeLessThanOrEqual(5);

        if (firstPage.pagination.hasMore && firstPage.pagination.nextCursor) {
          // Fetch second page using cursor
          const secondPage = await fetchEmailsByCriteria(criteria, {
            limit: 5,
            cursor: firstPage.pagination.nextCursor,
          });

          expect(secondPage.items.length).toBeLessThanOrEqual(5);

          // Ensure no overlap between pages
          const firstIds = firstPage.items.map((e) => e.id);
          const secondIds = secondPage.items.map((e) => e.id);
          const overlap = firstIds.filter((id) => secondIds.includes(id));
          expect(overlap).toHaveLength(0);
        }
      });

      it('should indicate hasMore correctly', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          limit: 1,
        };

        const result = await fetchEmailsByCriteria(criteria, pagination);

        // If only 1 item returned, hasMore depends on total count
        expect(typeof result.pagination.hasMore).toBe('boolean');
      });

      it('should return totalCount when requested', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          limit: 10,
          includeTotalCount: true,
        };

        const result = await fetchEmailsByCriteria(criteria, pagination);

        expect(typeof result.pagination.totalCount).toBe('number');
        expect(result.pagination.totalCount).toBeGreaterThanOrEqual(result.items.length);
      });

      it('should handle last page correctly (no more results)', async () => {
        const criteria: EmailQueryCriteria = {
          dateRange: {
            start: new Date('2020-01-01'),
            end: new Date('2020-01-02'),
          },
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(result.pagination.hasMore).toBe(false);
        expect(result.pagination.nextCursor).toBeUndefined();
      });
    });

    describe('Sorting', () => {
      it('should sort by date descending (newest first) by default', async () => {
        const criteria: EmailQueryCriteria = {};

        const result = await fetchEmailsByCriteria(criteria);

        if (result.items.length > 1) {
          for (let i = 1; i < result.items.length; i++) {
            expect(result.items[i - 1].date.getTime()).toBeGreaterThanOrEqual(result.items[i].date.getTime());
          }
        }
      });

      it('should support sort by date ascending', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          sortBy: 'date',
          sortOrder: 'asc',
        };

        const result = await fetchEmailsByCriteria(criteria, pagination);

        if (result.items.length > 1) {
          for (let i = 1; i < result.items.length; i++) {
            expect(result.items[i - 1].date.getTime()).toBeLessThanOrEqual(result.items[i].date.getTime());
          }
        }
      });

      it('should support sort by confidence', async () => {
        const criteria: EmailQueryCriteria = {
          isProcessed: true,
        };
        const pagination: PaginationOptions = {
          sortBy: 'confidence',
          sortOrder: 'desc',
        };

        const result = await fetchEmailsByCriteria(criteria, pagination);

        expect(Array.isArray(result.items)).toBe(true);
        // Note: requires JOIN with classification results and confidence ordering
      });
    });

    describe('Performance Optimization', () => {
      it('should use proper indexes for date range queries', async () => {
        const criteria: EmailQueryCriteria = {
          dateRange: {
            start: new Date('2025-01-01'),
            end: new Date('2025-12-31'),
          },
        };

        const startTime = Date.now();
        const result = await fetchEmailsByCriteria(criteria);
        const duration = Date.now() - startTime;

        expect(Array.isArray(result.items)).toBe(true);
        // Performance: should complete in reasonable time (< 1000ms for indexed query)
        expect(duration).toBeLessThan(1000);
      });

      it('should handle large result sets efficiently with pagination', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          limit: 100,
        };

        const startTime = Date.now();
        const result = await fetchEmailsByCriteria(criteria, pagination);
        const duration = Date.now() - startTime;

        expect(result.items.length).toBeLessThanOrEqual(100);
        // Should handle 100 items efficiently (< 500ms)
        expect(duration).toBeLessThan(500);
      });

      it('should optimize totalCount calculation with separate query', async () => {
        const criteria: EmailQueryCriteria = {
          dateRange: {
            start: new Date('2025-01-01'),
            end: new Date('2025-12-31'),
          },
        };
        const pagination: PaginationOptions = {
          limit: 10,
          includeTotalCount: true,
        };

        const result = await fetchEmailsByCriteria(criteria, pagination);

        expect(typeof result.pagination.totalCount).toBe('number');
        // Count should be >= items returned
        expect(result.pagination.totalCount).toBeGreaterThanOrEqual(result.items.length);
      });
    });

    describe('Error Handling', () => {
      it('should throw error for invalid date range in criteria', async () => {
        const criteria: EmailQueryCriteria = {
          dateRange: {
            start: new Date('2025-12-31'),
            end: new Date('2025-01-01'),
          },
        };

        await expect(fetchEmailsByCriteria(criteria)).rejects.toThrow(/invalid.*date.*range/i);
      });

      it('should throw error for negative limit', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          limit: -10,
        };

        await expect(fetchEmailsByCriteria(criteria, pagination)).rejects.toThrow(/invalid.*limit/i);
      });

      it('should throw error for limit exceeding maximum', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          limit: 10000, // Exceeds reasonable max (e.g., 1000)
        };

        await expect(fetchEmailsByCriteria(criteria, pagination)).rejects.toThrow(/limit.*exceeds.*maximum/i);
      });

      it('should throw error for invalid cursor format', async () => {
        const criteria: EmailQueryCriteria = {};
        const pagination: PaginationOptions = {
          cursor: 'invalid-cursor-format',
        };

        await expect(fetchEmailsByCriteria(criteria, pagination)).rejects.toThrow(/invalid.*cursor/i);
      });

      it('should handle invalid confidence range gracefully', async () => {
        const criteria: EmailQueryCriteria = {
          minConfidence: 1.5, // Invalid: should be 0.0 - 1.0
        };

        await expect(fetchEmailsByCriteria(criteria)).rejects.toThrow(/invalid.*confidence/i);
      });
    });

    describe('Edge Cases', () => {
      it('should return empty result for criteria matching no records', async () => {
        const criteria: EmailQueryCriteria = {
          subject: 'EXTREMELY_UNLIKELY_SUBJECT_XYZ123',
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(result.items).toEqual([]);
        expect(result.pagination.hasMore).toBe(false);
        expect(result.pagination.nextCursor).toBeUndefined();
      });

      it('should handle special characters in search criteria', async () => {
        const criteria: EmailQueryCriteria = {
          subject: "O'Reilly",
        };

        // Should not throw SQL injection errors
        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
      });

      it('should handle Unicode characters in search criteria', async () => {
        const criteria: EmailQueryCriteria = {
          subject: '日本語 测试 тест',
        };

        const result = await fetchEmailsByCriteria(criteria);

        expect(Array.isArray(result.items)).toBe(true);
      });
    });
  });
});

