     1→/**
     2→ * Database email query service (T036h + T048)
     3→ *
     4→ * Comprehensive query service for email testing and debugging with:
     5→ * - Basic queries (date range, by ID, unclassified) - T036h
     6→ * - Criteria-based selection with flexible filtering - T048
     7→ * - Cursor-based pagination for efficient large result handling - T048
     8→ * - Performance optimizations with proper indexing - T048
     9→ *
    10→ * Core Functions:
    11→ * - fetchEmailsByDateRange: Fetch emails within date range for batch testing (T036h)
    12→ * - fetchEmailById: Fetch single email for isolated testing (T036h)
    13→ * - fetchUnclassifiedEmails: Fetch emails without classification_session records (T036h)
    14→ * - fetchEmailsByCriteria: Advanced criteria-based query with pagination (T048)
    15→ */
    16→
    17→import { Pool } from 'pg';
    18→import {
    19→  type EmailMessage,
    20→  type EmailAddress,
    21→  type EmailHeader,
    22→  type MessagePart,
    23→  type MessagePartBody,
    24→} from '@gmail-automation/classification-engine';
    25→import { createPool } from '../database/db-utils';
    26→import * as fs from 'fs';
    27→import * as dotenv from 'dotenv';
    28→import * as path from 'path';
    29→
    30→// ========== Criteria-Based Query Types ==========
    31→
    32→/**
    33→ * Email query criteria for flexible filtering
    34→ */
    35→export interface EmailQueryCriteria {
    36→  // Text-based filters
    37→  subject?: string; // Case-insensitive substring match
    38→  from?: string; // Case-insensitive substring match on email address
    39→  bodyContains?: string; // Case-insensitive search in body_text or body_html
    40→
    41→  // Date range filter
    42→  dateRange?: {
    43→    start: Date;
    44→    end: Date;
    45→  };
    46→
    47→  // Gmail label filters (OR logic - matches any label)
    48→  gmailLabels?: string[];
    49→
    50→  // Processing status
    51→  isProcessed?: boolean;
    52→
    53→  // Classification filters (require JOIN with classification tables)
    54→  primaryCategory?: string; // Filter by primary category
    55→  minConfidence?: number; // Minimum classification confidence (0.0 - 1.0)
    56→  urgency?: 'low' | 'medium' | 'high'; // Filter by urgency attribute
    57→}
    58→
    59→/**
    60→ * Pagination options for query results
    61→ */
    62→export interface PaginationOptions {
    63→  // Limit number of results (default: 50, max: 1000)
    64→  limit?: number;
    65→
    66→  // Cursor for pagination (opaque string: base64-encoded timestamp+id)
    67→  cursor?: string;
    68→
    69→  // Sort options
    70→  sortBy?: 'date' | 'confidence';
    71→  sortOrder?: 'asc' | 'desc';
    72→
    73→  // Include total count in response (requires separate COUNT query)
    74→  includeTotalCount?: boolean;
    75→}
    76→
    77→/**
    78→ * Paginated query result
    79→ */
    80→export interface PaginatedResult<T> {
    81→  items: T[];
    82→  pagination: {
    83→    limit: number;
    84→    hasMore: boolean;
    85→    nextCursor?: string;
    86→    totalCount?: number;
    87→  };
    88→}
    89→
    90→/**
    91→ * Cursor structure for pagination
    92→ */
    93→interface Cursor {
    94→  timestamp: string; // ISO 8601 timestamp
    95→  id: string; // Email ID for tie-breaking
    96→}
    97→
    98→/**
    99→ * Connection pool using standard db-utils
   100→ */
   101→let pool: Pool | null = null;
   102→
   103→/**
   104→ * Detect if running in container environment (same logic as connect-as.sh)
   105→ */
   106→function detectPostgresHost(): string {
   107→  const envHost = process.env.POSTGRES_HOST;
   108→  if (envHost && envHost !== 'localhost') {
   109→    return envHost;
   110→  }
   111→
   112→  // Check if running in container (/.dockerenv or /run/.containerenv exists)
   113→  if (fs.existsSync('/.dockerenv') || fs.existsSync('/run/.containerenv')) {
   114→    return 'pg-n8n-local';
   115→  }
   116→
   117→  return 'localhost';
   118→}
   119→
   120→function getPool(): Pool {
   121→  if (!pool) {
   122→    // Load environment from project-init/.env if not already set
   123→    if (!process.env.PROJECT_DB_NAME) {
   124→      dotenv.config({ path: path.resolve(__dirname, '../../../../database/project-init/.env') });
   125→    }
   126→
   127→    const host = detectPostgresHost();
   128→
   129→    // Use db-utils createPool with container-aware host detection
   130→    pool = createPool({
   131→      host,
   132→      idleTimeoutMillis: 30000,
   133→      connectionTimeoutMillis: 2000,
   134→    });
   135→  }
   136→  return pool;
   137→}
