   236→/**
   237→ * Fetch emails within specified date range
   238→ *
   239→ * @param startDate - Start of date range (inclusive)
   240→ * @param endDate - End of date range (inclusive)
   241→ * @param limit - Maximum number of emails to return (default: 100)
   242→ * @returns Array of EmailMessage objects
   243→ */
   244→export async function fetchEmailsByDateRange(
   245→  startDate: Date,
   246→  endDate: Date,
   247→  limit: number = 100
   248→): Promise<EmailMessage[]> {
   249→  // Validate date range
   250→  if (startDate > endDate) {
   251→    throw new Error('Invalid date range: start date must be before end date');
   252→  }
   253→
   254→  const pool = getPool();
   255→
   256→  const query = `
   257→    SELECT
   258→      gm.gmail_id,
   259→      gm.gmail_thread_id,
   260→      gm.label_ids,
   261→      gm.subject,
   262→      gm.sent_at,
   263→      gm.message_id_hdr,
   264→      gm.from_simple,
   265→      gm.to_addrs,
   266→      gm.reply_to_addrs,
   267→      gm.headers,
   268→      gm.body_text,
   269→      gm.body_html,
   270→      gm.raw,
   271→      gm.size_estimate,
   272→      cs.session_id,
   273→      cs.completed_at
   274→    FROM email.gmail_message gm
   275→    LEFT JOIN LATERAL (
   276→      SELECT session_id, completed_at
   277→      FROM email.classification_session
   278→      WHERE gmail_id = gm.gmail_id
   279→      ORDER BY started_at DESC
   280→      LIMIT 1
   281→    ) cs ON true
   282→    WHERE gm.sent_at >= $1 AND gm.sent_at <= $2
   283→    ORDER BY gm.sent_at DESC
   284→    LIMIT $3
   285→  `;
   286→
   287→  try {
   288→    const result = await pool.query(query, [startDate, endDate, limit]);
   289→    return result.rows.map(mapRowToEmailMessage);
   290→  } catch (error) {
   291→    throw new Error(`Failed to fetch emails by date range: ${(error as Error).message}`);
   292→  }
   293→}
   294→
   295→/**
   296→ * Fetch single email by Gmail message ID
   297→ *
   298→ * @param messageId - Gmail message ID
   299→ * @returns EmailMessage object
   300→ * @throws Error if message not found or messageId is invalid
   301→ */
   302→export async function fetchEmailById(messageId: string): Promise<EmailMessage> {
   303→  // Validate input
   304→  if (!messageId || typeof messageId !== 'string' || messageId.trim() === '') {
   305→    throw new Error('Message ID is required and must be a non-empty string');
   306→  }
   307→
   308→  const pool = getPool();
   309→
   310→  const query = `
   311→    SELECT
   312→      gm.gmail_id,
   313→      gm.gmail_thread_id,
   314→      gm.label_ids,
   315→      gm.subject,
   316→      gm.sent_at,
   317→      gm.message_id_hdr,
   318→      gm.from_simple,
   319→      gm.to_addrs,
   320→      gm.reply_to_addrs,
   321→      gm.headers,
   322→      gm.body_text,
   323→      gm.body_html,
   324→      gm.raw,
   325→      gm.size_estimate,
   326→      cs.session_id,
   327→      cs.completed_at
   328→    FROM email.gmail_message gm
   329→    LEFT JOIN LATERAL (
   330→      SELECT session_id, completed_at
   331→      FROM email.classification_session
   332→      WHERE gmail_id = gm.gmail_id
   333→      ORDER BY started_at DESC
   334→      LIMIT 1
   335→    ) cs ON true
   336→    WHERE gm.gmail_id = $1
   337→  `;
   338→
   339→  try {
   340→    const result = await pool.query(query, [messageId]);
   341→
   342→    if (result.rows.length === 0) {
   343→      throw new Error(`Email with message ID "${messageId}" not found in database`);
   344→    }
   345→
   346→    return mapRowToEmailMessage(result.rows[0]);
   347→  } catch (error) {
   348→    if ((error as Error).message.includes('not found')) {
   349→      throw error;
   350→    }
   351→    throw new Error(`Failed to fetch email by ID: ${(error as Error).message}`);
   352→  }
   353→}
   354→
   355→/**
   356→ * Fetch emails without classification_session records
   357→ *
   358→ * @param limit - Maximum number of emails to return (default: 100)
   359→ * @returns Array of unclassified EmailMessage objects
   360→ */
   361→export async function fetchUnclassifiedEmails(limit: number = 100): Promise<EmailMessage[]> {
   362→  const pool = getPool();
   363→
   364→  const query = `
   365→    SELECT
   366→      gm.gmail_id,
   367→      gm.gmail_thread_id,
   368→      gm.label_ids,
   369→      gm.subject,
   370→      gm.sent_at,
   371→      gm.message_id_hdr,
   372→      gm.from_simple,
   373→      gm.to_addrs,
   374→      gm.reply_to_addrs,
   375→      gm.headers,
   376→      gm.body_text,
   377→      gm.body_html,
   378→      gm.raw,
   379→      gm.size_estimate,
   380→      NULL as session_id,
   381→      NULL as completed_at
   382→    FROM email.gmail_message gm
   383→    LEFT JOIN email.classification_session cs ON gm.gmail_id = cs.gmail_id
   384→    WHERE cs.session_id IS NULL
   385→    ORDER BY gm.sent_at DESC
   386→    LIMIT $1
   387→  `;
   388→
   389→  try {
   390→    const result = await pool.query(query, [limit]);
   391→    return result.rows.map(mapRowToEmailMessage);
   392→  } catch (error) {
   393→    throw new Error(`Failed to fetch unclassified emails: ${(error as Error).message}`);
   394→  }
   395→}
