   397→/**
   398→ * Encode cursor for pagination
   399→ */
   400→function encodeCursor(cursor: Cursor): string {
   401→  const json = JSON.stringify(cursor);
   402→  return Buffer.from(json).toString('base64');
   403→}
   404→
   405→/**
   406→ * Decode cursor for pagination
   407→ */
   408→function decodeCursor(cursorStr: string): Cursor {
   409→  try {
   410→    const json = Buffer.from(cursorStr, 'base64').toString('utf-8');
   411→    const cursor = JSON.parse(json) as Cursor;
   412→
   413→    // Validate cursor structure
   414→    if (!cursor.timestamp || !cursor.id) {
   415→      throw new Error('Invalid cursor structure');
   416→    }
   417→
   418→    // Validate timestamp format
   419→    if (isNaN(new Date(cursor.timestamp).getTime())) {
   420→      throw new Error('Invalid cursor timestamp');
   421→    }
   422→
   423→    return cursor;
   424→  } catch (error) {
   425→    throw new Error(`Invalid cursor format: ${(error as Error).message}`);
   426→  }
   427→}
   428→
   429→/**
   430→ * Build WHERE clause from criteria
   431→ */
   432→function buildWhereClause(
   433→  criteria: EmailQueryCriteria,
   434→  paramOffset: number = 0
   435→): { clause: string; params: unknown[] } {
   436→  const conditions: string[] = [];
   437→  const params: unknown[] = [];
   438→  let paramIndex = paramOffset + 1;
   439→
   440→  // Subject filter
   441→  if (criteria.subject) {
   442→    conditions.push(`gm.subject ILIKE $${paramIndex}`);
   443→    params.push(`%${criteria.subject}%`);
   444→    paramIndex++;
   445→  }
   446→
   447→  // From filter
   448→  if (criteria.from) {
   449→    conditions.push(`(gm.from_simple::text ILIKE $${paramIndex})`);
   450→    params.push(`%${criteria.from}%`);
   451→    paramIndex++;
   452→  }
   453→
   454→  // Body contains filter
   455→  if (criteria.bodyContains) {
   456→    conditions.push(`(gm.body_text ILIKE $${paramIndex} OR gm.body_html ILIKE $${paramIndex})`);
   457→    params.push(`%${criteria.bodyContains}%`);
   458→    paramIndex++;
   459→  }
   460→
   461→  // Date range filter
   462→  if (criteria.dateRange) {
   463→    conditions.push(`gm.sent_at >= $${paramIndex}`);
   464→    params.push(criteria.dateRange.start);
   465→    paramIndex++;
   466→
   467→    conditions.push(`gm.sent_at <= $${paramIndex}`);
   468→    params.push(criteria.dateRange.end);
   469→    paramIndex++;
   470→  }
   471→
   472→  // Gmail labels filter (OR logic)
   473→  if (criteria.gmailLabels && criteria.gmailLabels.length > 0) {
   474→    conditions.push(`gm.label_ids && $${paramIndex}::text[]`);
   475→    params.push(criteria.gmailLabels);
   476→    paramIndex++;
   477→  }
   478→
   479→  // Processing status filter
   480→  if (criteria.isProcessed !== undefined) {
   481→    if (criteria.isProcessed) {
   482→      conditions.push('cs.session_id IS NOT NULL');
   483→    } else {
   484→      conditions.push('cs.session_id IS NULL');
   485→    }
   486→  }
   487→
   488→  // Primary category filter (requires JOIN with session_categories)
   489→  if (criteria.primaryCategory) {
   490→    conditions.push(`sc.is_primary = true`);
   491→    // Note: We need to join with category table to filter by code
   492→    conditions.push(`cat.code = $${paramIndex}`);
   493→    params.push(criteria.primaryCategory);
   494→    paramIndex++;
   495→  }
   496→
   497→  // Minimum confidence filter (requires JOIN with classification_session)
   498→  if (criteria.minConfidence !== undefined) {
   499→    conditions.push(`cs.confidence >= $${paramIndex}`);
   500→    params.push(criteria.minConfidence);
   501→    paramIndex++;
   502→  }
   503→
   504→  // Urgency filter (requires JOIN with detected_attribute)
   505→  if (criteria.urgency) {
   506→    conditions.push(`da.attribute_name = 'urgency'`);
   507→    conditions.push(`da.attribute_value = $${paramIndex}`);
   508→    params.push(criteria.urgency);
   509→    paramIndex++;
   510→  }
   511→
   512→  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
   513→  return { clause: whereClause, params };
   514→}
   515→
   516→/**
   517→ * Build FROM clause with necessary JOINs based on criteria
   518→ */
   519→function buildFromClause(criteria: EmailQueryCriteria, pagination?: PaginationOptions): string {
   520→  let fromClause = 'FROM email.gmail_message gm';
   521→
   522→  // Always LEFT JOIN classification_session for processing status
   523→  fromClause += `
   524→    LEFT JOIN LATERAL (
   525→      SELECT session_id, completed_at, final_confidence as confidence
   526→      FROM email.classification_session
   527→      WHERE gmail_id = gm.gmail_id
   528→      ORDER BY started_at DESC
   529→      LIMIT 1
   530→    ) cs ON true`;
   531→
   532→  // JOIN session_categories and category if filtering by category
   533→  if (criteria.primaryCategory) {
   534→    fromClause += `
   535→    LEFT JOIN email.session_categories sc ON cs.session_id = sc.session_id
   536→    LEFT JOIN email.category cat ON sc.category_id = cat.category_id`;
   537→  }
   538→
   539→  // JOIN detected_attributes if filtering by urgency
   540→  if (criteria.urgency) {
   541→    fromClause += `
   542→    LEFT JOIN email.detected_attributes da ON cs.session_id = da.session_id`;
   543→  }
   544→
   545→  // JOIN for confidence-based sorting
   546→  if (pagination?.sortBy === 'confidence') {
   547→    // Already have cs.confidence from classification_session JOIN
   548→  }
   549→
   550→  return fromClause;
   551→}
   552→
   553→/**
   554→ * Build ORDER BY clause
   555→ */
   556→function buildOrderByClause(pagination?: PaginationOptions): string {
   557→  const sortBy = pagination?.sortBy || 'date';
   558→  const sortOrder = pagination?.sortOrder || 'desc';
   559→
   560→  if (sortBy === 'confidence') {
   561→    return `ORDER BY cs.confidence ${sortOrder.toUpperCase()}, gm.sent_at DESC`;
   562→  }
   563→
   564→  // Default: sort by date
   565→  return `ORDER BY gm.sent_at ${sortOrder.toUpperCase()}`;
   566→}
   567→
   568→/**
   569→ * Validate criteria and pagination options
   570→ */
   571→function validateCriteriaAndPagination(criteria: EmailQueryCriteria, pagination?: PaginationOptions): void {
   572→  // Validate date range
   573→  if (criteria.dateRange) {
   574→    if (criteria.dateRange.start > criteria.dateRange.end) {
   575→      throw new Error('Invalid date range: start date must be before end date');
   576→    }
   577→  }
   578→
   579→  // Validate confidence range
   580→  if (criteria.minConfidence !== undefined) {
   581→    if (criteria.minConfidence < 0 || criteria.minConfidence > 1) {
   582→      throw new Error('Invalid confidence: must be between 0.0 and 1.0');
   583→    }
   584→  }
   585→
   586→  // Validate pagination limit
   587→  if (pagination?.limit !== undefined) {
   588→    if (pagination.limit < 0) {
   589→      throw new Error('Invalid limit: must be non-negative');
   590→    }
   591→    if (pagination.limit > 1000) {
   592→      throw new Error('Limit exceeds maximum allowed value of 1000');
   593→    }
   594→  }
   595→}
   596→
   597→/**
   598→ * Fetch emails with criteria-based selection and pagination (T048)
   599→ *
   600→ * @param criteria - Query criteria for filtering
   601→ * @param pagination - Pagination options (limit, cursor, sort)
   602→ * @returns Paginated result with email messages
   603→ */
   604→export async function fetchEmailsByCriteria(
   605→  criteria: EmailQueryCriteria,
   606→  pagination?: PaginationOptions
   607→): Promise<PaginatedResult<EmailMessage>> {
   608→  // Validate inputs
   609→  validateCriteriaAndPagination(criteria, pagination);
   610→
   611→  const pool = getPool();
   612→
   613→  // Pagination defaults
   614→  const limit = pagination?.limit || 50;
   615→  const includeTotalCount = pagination?.includeTotalCount || false;
   616→
   617→  // Decode cursor if provided
   618→  let cursorData: Cursor | null = null;
   619→  if (pagination?.cursor) {
   620→    cursorData = decodeCursor(pagination.cursor);
   621→  }
   622→
   623→  // Build query components
   624→  const { clause: whereClause, params } = buildWhereClause(criteria);
   625→  const fromClause = buildFromClause(criteria, pagination);
   626→  const orderByClause = buildOrderByClause(pagination);
   627→
   628→  // Add cursor conditions to WHERE clause
   629→  let cursorCondition = '';
   630→  let cursorParams: unknown[] = [];
   631→  if (cursorData) {
   632→    const cursorParamIndex = params.length + 1;
   633→    const sortOrder = pagination?.sortOrder || 'desc';
   634→
   635→    if (sortOrder === 'desc') {
   636→      cursorCondition = `AND (gm.sent_at < $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id < $${cursorParamIndex + 1}))`;
   637→    } else {
   638→      cursorCondition = `AND (gm.sent_at > $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id > $${cursorParamIndex + 1}))`;
   639→    }
   640→    cursorParams = [cursorData.timestamp, cursorData.id];
   641→  }
   642→
   643→  // Construct main query (fetch limit + 1 to determine hasMore)
   644→  const query = `
   645→    SELECT
   646→      gm.gmail_id,
   647→      gm.gmail_thread_id,
   648→      gm.label_ids,
   649→      gm.subject,
   650→      gm.sent_at,
   651→      gm.message_id_hdr,
   652→      gm.from_simple,
   653→      gm.to_addrs,
   654→      gm.reply_to_addrs,
   655→      gm.headers,
   656→      gm.body_text,
   657→      gm.body_html,
   658→      gm.raw,
   659→      gm.size_estimate,
   660→      cs.session_id,
   661→      cs.completed_at
   662→    ${fromClause}
   663→    ${whereClause} ${cursorCondition}
   664→    ${orderByClause}
   665→    LIMIT $${params.length + cursorParams.length + 1}
   666→  `;
   667→
   668→  const queryParams = [...params, ...cursorParams, limit + 1];
   669→
   670→  try {
   671→    // Execute main query
   672→    const result = await pool.query(query, queryParams);
   673→
   674→    // Determine hasMore and prepare items
   675→    const hasMore = result.rows.length > limit;
   676→    const items = result.rows.slice(0, limit).map(mapRowToEmailMessage);
   677→
   678→    // Generate nextCursor if hasMore
   679→    let nextCursor: string | undefined;
   680→    if (hasMore && items.length > 0) {
   681→      const lastItem = items[items.length - 1];
   682→      nextCursor = encodeCursor({
   683→        timestamp: lastItem.date.toISOString(),
   684→        id: lastItem.id,
   685→      });
   686→    }
   687→
   688→    // Fetch total count if requested (separate query for performance)
   689→    let totalCount: number | undefined;
   690→    if (includeTotalCount) {
   691→      const countQuery = `
   692→        SELECT COUNT(*) as count
   693→        ${fromClause}
   694→        ${whereClause}
   695→      `;
   696→
   697→      const countResult = await pool.query(countQuery, params);
   698→      totalCount = parseInt(countResult.rows[0].count, 10);
   699→    }
   700→
   701→    return {
   702→      items,
   703→      pagination: {
   704→        limit,
   705→        hasMore,
   706→        nextCursor,
   707→        totalCount,
   708→      },
   709→    };
   710→  } catch (error) {
   711→    throw new Error(`Failed to fetch emails by criteria: ${(error as Error).message}`);
   712→  }
   713→}
   714→
   715→/**
   716→ * Close the connection pool (for testing cleanup)
   717→ */
   718→export async function closePool(): Promise<void> {
   719→  if (pool) {
   720→    await pool.end();
   721→    pool = null;
   722→  }
   723→}
